var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이거 놔! 빌어먹을 늙다리!","JPN":"放せ！　クソジジイ！","ENG":"Get off of me, you bloody old man!","TWN":"把我放下！你這該死的老頭！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대체 사람을 어디로 끌고 가는 거야!","JPN":"いったいどこに連れてこうってんだよ！","ENG":"Where are you taking me?","TWN":"你到底要把我帶到哪裡去啊！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하핫. 카지노에서 두들겨 맞을 뻔한 걸 구해 줬더니 고맙다는 말도 없군.","JPN":"ハハッ。カジノで袋叩きにされそうだったところを助けてやったのに、お礼も言えないのか。","ENG":"Hah hah! I saved your bacon from those angry gamblers at the casino. You should be thanking me.","TWN":"哈哈。我明明救了在賭場差點挨揍的你，結果連句感謝的話都沒有啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"왜 괜히 끼어들어서 판을 뒤집으려고 드나?","JPN":"なんでわざわざゲームをメチャクチャにしようとしたんだ？","ENG":"Why did you have to stick your nose in their games in the first place?","TWN":"為什麼要無緣無故插手管這件事？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"속임수 쓰는 놈이 있는데 멍청하게 돈 갖다 바치는 녀석들이 안쓰러워서 그랬다, 왜?","JPN":"相手がイカサマしてるのに、馬鹿みたいに\\n全財産を賭けようとしてる奴らが哀れだったんだよ！\\n悪いか？","ENG":"I was feeling sorry for those twits who didn't even know they were being scammed. So what?","TWN":"看到有人笨笨地把錢獻給出老千的傢伙，因為實在太可悲了我才這麼做的，怎嘛？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"혈기왕성하군.","JPN":"血気旺盛だな。","ENG":"You're one feisty young man.","TWN":"真是血氣方剛啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 정의감으로 나서는 것도 상황 봐 가면서 해야지.","JPN":"だが、正義感から手を出すにしても状況は見るべきだろう。","ENG":"But you should be careful not to let your sense of justice get you into trouble.","TWN":"但表現正義感之前還是得先看清楚情況吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"웃기시네! 백주대낮에 사람을 납치하면서 뭐 그리 뻔뻔해?","JPN":"ふざけんな！　真昼間から人を拉致してるくせに、図々しいじじいだな！","ENG":"Hah! Says an old crook who's kidnapping a person in broad daylight.","TWN":"真是搞笑！光天化日之下綁架別人，還說得這麼大言不慚？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자고로 신사는 언제 어디서나 여유가 있어야 하는 법이야.","JPN":"紳士たるもの、いつでもどこでも余裕を持たなければ。","ENG":"A gentleman should be able to keep his composure at any time and place.","TWN":"自古以來，紳士無論何時何地，都要表現得遊刃有餘啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 불안해하면 볼썽사납다네.","JPN":"そんなにビビっているのは見苦しいぞ。","ENG":"He shouldn't express his fear and anxiety so bluntly.","TWN":"表現出慌張不安的樣子，實在太失體面了。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그딴 소리는 놓고나 말하라고! 이 망할 할배가 진짜!!","JPN":"だったら放せよな！　このくそじじい！","ENG":"I'll pretend to listen if you let go of me. Come on, you barmy codger!","TWN":"不准說這種話！你這個該死的老頭！！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까...... 그녀가 그 동안 그라운드 원의 대학원에서 재학 중이었다는 말인가요?","JPN":"つまり……彼女はこれまでグラウンド・ワンの大学院に在学中だったということですか？","ENG":"So... She has been studying at a graduate school in Ground One until now.","TWN":"所以……你是說，她這段時間一直在Ground 1的研究所念書？"},"stage":{"bg":"SS_ESPR_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"네, 아가씨.","JPN":"はい、お嬢様。","ENG":"Yes, Lady Elizabeth.","TWN":"是的，小姐。"},"stage":{"bg":"SS_ESPR_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"조사에 따르면 최근에 어머니의 부고를 받고 영지로 돌아갔다고 합니다.","JPN":"調査によると最近、母親の訃報を受けて領地に戻ったそうです。","ENG":"Our recent investigation discovered that she returned to the estate after hearing of her mother's death.","TWN":"根據調查，她是最近接到母親的訃告，才回到麥克蕾蒂領地的。"},"stage":{"bg":"SS_ESPR_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"과연. 그래서 맥크레디 포인트에 자유롭게 드나들 수 있었던 거군요.","JPN":"なるほど。それでマクレディーポイントを自由に歩き回れたのですね。","ENG":"I see. That's why she was able to move in and out of MacCready Point freely.","TWN":"原來如此。所以她才能自由出入麥克蕾蒂要點啊。"},"stage":{"bg":"SS_ESPR_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 자신이 누구인지는 전혀 몰랐던 모양이죠?","JPN":"でも、自分が何者かはまったく知らなかったようですけれど。","ENG":"So she had no idea who she was?","TWN":"但她好像完全不知道自己是什麼人的樣子？"},"stage":{"bg":"SS_ESPR_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};